#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double salary;
        scanf("%lf", &salary);
        double grossSalary;
        if (salary < 1500) {
            grossSalary = salary + (salary * 0.1) + (salary * 0.9);
        } else {
            grossSalary = salary + 500 + (salary * 0.98);
        }
        printf("%.2f\n", grossSalary);
    }
    return 0;
}

